import React from 'react';
import { BrowserRouter as Router, Route, Routes, Navigate } from 'react-router-dom';
import EmployeeList from './components/EmployeeList';
import AddEmployee from './components/AddEmployee';
import EditEmployee from './components/EditEmployee';
import Login from './components/Login';
import Home from './components/Home';

function App() {
  const isAuthenticated = !!localStorage.getItem('token'); // Kontrola prihlásenia

  return (
    <Router>
      <Routes>
        <Route path="/login" element={<Login />} />
        <Route path="/" element={isAuthenticated ? <Home /> : <Navigate to="/login" />} />
        <Route path="/employees" element={isAuthenticated ? <EmployeeList /> : <Navigate to="/login" />} />
        <Route path="/add-employee" element={isAuthenticated ? <AddEmployee /> : <Navigate to="/login" />} />
        <Route path="/edit-employee/:id" element={isAuthenticated ? <EditEmployee /> : <Navigate to="/login" />} />
      </Routes>
    </Router>
  );
}

export default App;
